VALUES ('rel_parent_crisis_001', 'relationship', 'Проблемы с родителями', 'Твои родители переживают трудный период и просят твоей помощи и поддержки.', 16, 40, '{}'::jsonb, '[{"text_ru": "Помочь финансово", "consequences": {"money": -10000, "social": 25, "happiness": 15, "energy": -20}}, {"text_ru": "Провести больше времени с ними", "consequences": {"money": -3000, "social": 30, "happiness": 20, "energy": -15}}, {"text_ru": "Посоветовать обратиться к специалистам", "consequences": {"money": -1000, "social": 15, "happiness": 10, "energy": -5}}]'::jsonb, '{"modifies_relationships": ["parent"], "is_repeatable": true, "cooldown_days": 14, "tags": ["family", "parents", "support"], "category_code": 5}'::jsonb)
