VALUES ('rel_friend_help_001', 'relationship', 'Друг просит о помощи', 'Твой лучший друг оказался в сложной ситуации и отчаянно просит твоей помощи.', 18, 100, '{}'::jsonb, '[{"text_ru": "Оказать полную поддержку", "consequences": {"money": -15000, "social": 35, "happiness": 25, "energy": -25}}, {"text_ru": "Помочь финансово, но не лично", "consequences": {"money": -8000, "social": 20, "happiness": 15, "energy": -10}}, {"text_ru": "Посоветовать обратиться к профессионалам", "consequences": {"money": -500, "social": 10, "happiness": 5, "energy": -5}}]'::jsonb, '{"modifies_relationships": ["best_friend"], "is_repeatable": true, "cooldown_days": 10, "tags": ["friendship", "help", "crisis"], "category_code": 5}'::jsonb)
