INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('rel_romance_001', 'relationship', 'Новое знакомство', 'Ты познакомился с интересным человеком. Возникает симпатия и желание продолжить общение.', 16, 50, '{"social": 40}'::jsonb, '[{"text_ru": "Пригласить на свидание", "consequences": {"money": -3000, "social": 25, "happiness": 30, "energy": -15}}, {"text_ru": "Предложить дружбу", "consequences": {"money": -1000, "social": 20, "happiness": 15, "energy": -10}}, {"text_ru": "Оставить просто знакомым", "consequences": {"money": 0, "social": 5, "happiness": 5, "energy": -5}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 7, "tags": ["romance", "dating", "opportunity"], "category_code": 5}'::jsonb)
