VALUES ('rel_conflict_001', 'relationship', 'Конфликт с другом', 'Из-за недопонимания возник конфликт с близким другом. Отношения под угрозой.', 18, 100, '{}'::jsonb, '[{"text_ru": "Попытаться примириться", "consequences": {"money": -1000, "social": 20, "happiness": 15, "energy": -10}}, {"text_ru": "Дать время остыть", "consequences": {"money": 0, "social": -10, "happiness": -10, "energy": 10}}, {"text_ru": "Обратиться к общим друзьям", "consequences": {"money": -500, "social": 15, "happiness": 10, "energy": -5}}]'::jsonb, '{"modifies_relationships": ["friend"], "is_repeatable": true, "cooldown_days": 14, "tags": ["conflict", "friendship", "crisis"], "category_code": 5}'::jsonb)
