INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('rel_marriage_001', 'relationship', 'Предложение о браке', 'Твой партнер делает тебе предложение о браке. Это важное решение, которое изменит твою жизнь.', 22, 45, '{}'::jsonb, '[{"text_ru": "Согласиться на брак", "consequences": {"money": -20000, "social": 40, "happiness": 50, "energy": -20}}, {"text_ru": "Предложить пожить вместе сначала", "consequences": {"money": -5000, "social": 30, "happiness": 35, "energy": -15}}, {"text_ru": "Вежливо отказаться", "consequences": {"money": 2000, "social": -30, "happiness": -25, "energy": 10}}]'::jsonb, '{"required_relationships": {"partner": 80}, "is_repeatable": false, "tags": ["marriage", "commitment", "milestone"], "category_code": 5}'::jsonb)
