INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('rel_betrayal_001', 'relationship', 'Предательство', 'Человек, которому ты доверял, предал тебя. Это болезненный удар по твоим убеждениям.', 20, 100, '{}'::jsonb, '[{"text_ru": "Простить и попытаться сохранить отношения", "consequences": {"money": -2000, "social": 15, "happiness": -10, "energy": -10}}, {"text_ru": "Разорвать все отношения", "consequences": {"money": 0, "social": -40, "happiness": -30, "energy": 5}}, {"text_ru": "Потребовать объяснений", "consequences": {"money": -1000, "social": 5, "happiness": -5, "energy": -5}}]'::jsonb, '{"is_repeatable": false, "tags": ["betrayal", "trust", "crisis"], "category_code": 5}'::jsonb)
