VALUES ('rel_family_event_001', 'relationship', 'Семейное торжество', 'В твоей семье намечается важное событие - юбилей, свадьба или рождение ребёнка.', 18, 100, '{}'::jsonb, '[{"text_ru": "Активно участвовать в организации", "consequences": {"money": -5000, "social": 30, "happiness": 25, "energy": -25}}, {"text_ru": "Помочь финансово", "consequences": {"money": -10000, "social": 20, "happiness": 15, "energy": -15}}, {"text_ru": "Просто присутствовать", "consequences": {"money": -2000, "social": 15, "happiness": 10, "energy": -10}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 21, "tags": ["family", "celebration", "positive"], "category_code": 5}'::jsonb)
