VALUES ('rel_childbirth_001', 'relationship', 'Рождение ребёнка', 'У тебя родился ребёнок! Это радость, но и огромная ответственность.', 25, 45, '{}'::jsonb, '[{"text_ru": "Взять отпуск по уходу за ребёнком", "consequences": {"money": -15000, "social": 20, "happiness": 40, "energy": -30}}, {"text_ru": "Нанять няню", "consequences": {"money": -8000, "social": 10, "happiness": 30, "energy": -20}}, {"text_ru": "Просить помощи у родственников", "consequences": {"money": -5000, "social": 25, "happiness": 25, "energy": -25}}]'::jsonb, '{"required_relationships": {"partner": 90}, "is_repeatable": false, "tags": ["childbirth", "family", "milestone"], "category_code": 5}'::jsonb)
