INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('volaura_gold_recruit_001', 'volaura', 'Приглашение от организации', 'Международная организация нашла твой профиль на VOLAURA и видит, что у тебя Gold-уровень. Предлагают позицию с отличными условиями.', 20, 55, '{"intelligence": 60, "social": 40}'::jsonb, '[{"text_ru": "Принять предложение", "consequences": {"money": 40000, "work_experience": 35, "happiness": 40, "social": 20, "energy": -20}}, {"text_ru": "Обсудить условия", "consequences": {"money": 55000, "work_experience": 25, "happiness": 30, "social": 15, "energy": -10}}, {"text_ru": "Вежливо отказать — не моё направление", "consequences": {"happiness": 10, "social": 5, "energy": 10}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 30, "tags": ["volaura", "recruitment", "career"], "category_code": 3}'::jsonb)
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('volaura_assessment_unlock_001', 'volaura', 'Новый уровень AURA', 'Твои результаты на VOLAURA улучшились! Ты разблокировал доступ к продвинутым курсам и менторским программам.', 18, 80, '{"intelligence": 40}'::jsonb, '[{"text_ru": "Пройти продвинутый курс", "consequences": {"money": -5000, "intelligence": 25, "work_experience": 15, "energy": -25, "happiness": 20}}, {"text_ru": "Найти ментора", "consequences": {"money": -3000, "intelligence": 15, "social": 20, "work_experience": 10, "energy": -15}}, {"text_ru": "Поделиться успехом в социальных сетях", "consequences": {"social": 30, "happiness": 15, "energy": -5}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 21, "tags": ["volaura", "assessment", "growth"], "category_code": 4}'::jsonb)
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('volaura_crystal_course_001', 'volaura', 'Кристаллы — премиум обучение', 'У тебя накопилось достаточно кристаллов VOLAURA, чтобы разблокировать премиум-курс по лидерству.', 18, 60, '{"money": 5000}'::jsonb, '[{"text_ru": "Потратить кристаллы на курс", "consequences": {"money": -2000, "intelligence": 20, "social": 15, "work_experience": 20, "energy": -20, "happiness": 15}}, {"text_ru": "Копить кристаллы на что-то большее", "consequences": {"money": 1000, "happiness": 5, "energy": 5}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 14, "tags": ["volaura", "crystals", "education"], "category_code": 4}'::jsonb)
