INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('volaura_platinum_event_001', 'volaura', 'Platinum — элитный нетворкинг', 'Как обладатель Platinum-бейджа VOLAURA, ты приглашён на закрытое мероприятие для топ-специалистов. Здесь собираются CEO, инвесторы и лидеры индустрии.', 25, 65, '{"intelligence": 80, "social": 60}'::jsonb, '[{"text_ru": "Пойти и завести связи", "consequences": {"money": -5000, "social": 45, "work_experience": 20, "happiness": 35, "energy": -30}}, {"text_ru": "Предложить свой стартап инвесторам", "consequences": {"money": 50000, "work_experience": 30, "social": 25, "happiness": 50, "energy": -40}}, {"text_ru": "Пропустить — слишком формально для меня", "consequences": {"energy": 15, "happiness": -5, "social": -10}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 30, "tags": ["volaura", "platinum", "networking", "elite"], "category_code": 5}'::jsonb)
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('volaura_mindshift_streak_001', 'volaura', 'MindShift — серия фокус-сессий', 'Ты прошёл 7-дневную серию фокус-сессий в MindShift. Твоя концентрация и энергия заметно улучшились.', 16, 80, '{}'::jsonb, '[{"text_ru": "Продолжить серию — цель 30 дней", "consequences": {"health": 20, "energy": 25, "intelligence": 10, "happiness": 20, "money": -1000}}, {"text_ru": "Применить навыки на работе", "consequences": {"work_experience": 20, "energy": 15, "intelligence": 5, "money": 5000}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 7, "tags": ["mindshift", "focus", "health", "ecosystem"], "category_code": 10}'::jsonb)
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('volaura_career_coach_001', 'volaura', 'Карьерный коуч VOLAURA', 'VOLAURA предлагает услуги AI-карьерного коуча на основе твоего AURA-профиля. Гарантия следующего повышения.', 22, 50, '{"money": 7500}'::jsonb, '[{"text_ru": "Нанять коуча (75 кристаллов)", "consequences": {"money": -7500, "work_experience": 30, "intelligence": 10, "happiness": 20, "social": 10}}, {"text_ru": "Попробовать бесплатную консультацию", "consequences": {"work_experience": 10, "intelligence": 5, "happiness": 10, "energy": -5}}, {"text_ru": "Разобраться самому", "consequences": {"intelligence": 15, "energy": -15, "happiness": 5}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 21, "tags": ["volaura", "career", "coaching", "crystals"], "category_code": 3}'::jsonb)
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('work_promotion_001', 'work', 'Повышение на работе', 'Твой начальник заметил твою хорошую работу и предлагает повышение с увеличением зарплаты.', 22, 65, '{"work_experience": 30}'::jsonb, '[{"text_ru": "Согласиться на повышение", "consequences": {"money": 15000, "work_experience": 20, "energy": -20, "social": -5, "happiness": 25}}, {"text_ru": "Попросить о большей зарплате", "consequences": {"money": 20000, "work_experience": 15, "energy": -15, "social": -10, "happiness": 20}}, {"text_ru": "Вежливо отказаться", "consequences": {"money": 5000, "work_experience": 5, "energy": 10, "social": 15, "happiness": 10}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 14, "tags": ["promotion", "career"], "category_code": 3}'::jsonb)
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.lifesim_events (id, category, title_ru, description_ru, min_age, max_age, required_stats, choices, extra)
VALUES ('work_new_job_001', 'work', 'Предложение о новой работе', 'Тебе предложили работу в конкурирующей компании с лучшими условиями.', 20, 55, '{}'::jsonb, '[{"text_ru": "Перейти в новую компанию", "consequences": {"money": 25000, "work_experience": 25, "energy": -25, "social": -15, "happiness": 30}}, {"text_ru": "Попросить текущего работодателя о повышении", "consequences": {"money": 10000, "work_experience": 10, "energy": -10, "social": 5, "happiness": 15}}, {"text_ru": "Остаться на текущей работе", "consequences": {"money": 5000, "work_experience": 5, "energy": 5, "social": 10, "happiness": 5}}]'::jsonb, '{"is_repeatable": true, "cooldown_days": 21, "tags": ["job_change", "opportunity"], "category_code": 3}'::jsonb)
